CREATE SCHEMA IF NOT EXISTS "retrobolt_security";
CREATE OR REPLACE FUNCTION "retrobolt_security".current_app_user_id() RETURNS integer LANGUAGE plpgsql STABLE AS $$
BEGIN
  RETURN NULLIF(current_setting('retrobolt.app_user_id', true), '')::integer;
EXCEPTION WHEN invalid_text_representation THEN
  RETURN NULL;
END;
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_accessible_institution_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT institution_id), ARRAY[]::integer[])
  FROM (
    SELECT s.institution_id FROM "retrobolt_product_userrolegrantscope" s JOIN "retrobolt_product_userrolegrant" g ON g.id = s.grant_id JOIN "retrobolt_product_role" r ON r.id = g.role_id
    WHERE g.user_id = "retrobolt_security".current_app_user_id() AND s.institution_id IS NOT NULL AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind"
    UNION
    SELECT p.institution_id FROM "retrobolt_product_teacherresponsibilityassignment" tr JOIN "retrobolt_product_divisionsubjectoffering" o ON o.id = tr.offering_id JOIN "retrobolt_product_perioddivision" d ON d.id = o.division_id JOIN "retrobolt_product_periodgrade" pg ON pg.id = d.grade_id JOIN "retrobolt_product_institutionenrollmentperiod" p ON p.id = pg.period_id
    WHERE tr.user_id = "retrobolt_security".current_app_user_id() AND tr.active = true AND (tr.valid_from IS NULL OR tr.valid_from <= CURRENT_DATE) AND (tr.valid_to IS NULL OR tr.valid_to >= CURRENT_DATE)
  ) scoped
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_unscoped_institution_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT s.institution_id), ARRAY[]::integer[])
  FROM "retrobolt_product_userrolegrantscope" s JOIN "retrobolt_product_userrolegrant" g ON g.id = s.grant_id JOIN "retrobolt_product_role" r ON r.id = g.role_id
  WHERE g.user_id = "retrobolt_security".current_app_user_id()
    AND s.scope_type = 'institution' AND s.institution_id IS NOT NULL AND r.scope_kind = 'institution'
    AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind"
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_organization_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT organization_id), ARRAY[]::integer[])
  FROM (
    SELECT s.organization_id FROM "retrobolt_product_userrolegrantscope" s JOIN "retrobolt_product_userrolegrant" g ON g.id = s.grant_id JOIN "retrobolt_product_role" r ON r.id = g.role_id WHERE g.user_id = "retrobolt_security".current_app_user_id() AND s.organization_id IS NOT NULL AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind"
    UNION
    SELECT i.organization_id FROM "retrobolt_product_teacherresponsibilityassignment" tr JOIN "retrobolt_product_divisionsubjectoffering" o ON o.id = tr.offering_id JOIN "retrobolt_product_perioddivision" d ON d.id = o.division_id JOIN "retrobolt_product_periodgrade" pg ON pg.id = d.grade_id JOIN "retrobolt_product_institutionenrollmentperiod" p ON p.id = pg.period_id JOIN "retrobolt_product_institution" i ON i.id = p.institution_id WHERE tr.user_id = "retrobolt_security".current_app_user_id() AND tr.active = true AND (tr.valid_from IS NULL OR tr.valid_from <= CURRENT_DATE) AND (tr.valid_to IS NULL OR tr.valid_to >= CURRENT_DATE)
  ) scoped
$$;
