CREATE OR REPLACE FUNCTION "retrobolt_security".current_subject_offering_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT offering_id), ARRAY[]::integer[])
  FROM (
    SELECT s.division_subject_offering_id AS offering_id FROM "retrobolt_product_userrolegrantscope" s JOIN "retrobolt_product_userrolegrant" g ON g.id = s.grant_id JOIN "retrobolt_product_role" r ON r.id = g.role_id WHERE g.user_id = "retrobolt_security".current_app_user_id() AND s.division_subject_offering_id IS NOT NULL AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind"
    UNION
    SELECT tr.offering_id FROM "retrobolt_product_teacherresponsibilityassignment" tr WHERE tr.user_id = "retrobolt_security".current_app_user_id() AND tr.active = true AND (tr.valid_from IS NULL OR tr.valid_from <= CURRENT_DATE) AND (tr.valid_to IS NULL OR tr.valid_to >= CURRENT_DATE)
  ) scoped
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_division_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT division_id), ARRAY[]::integer[])
  FROM (
    SELECT o.division_id FROM "retrobolt_product_userrolegrantscope" s JOIN "retrobolt_product_userrolegrant" g ON g.id = s.grant_id JOIN "retrobolt_product_role" r ON r.id = g.role_id JOIN "retrobolt_product_divisionsubjectoffering" o ON o.id = s.division_subject_offering_id WHERE g.user_id = "retrobolt_security".current_app_user_id() AND s.division_subject_offering_id IS NOT NULL AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind"
    UNION
    SELECT o.division_id FROM "retrobolt_product_teacherresponsibilityassignment" tr JOIN "retrobolt_product_divisionsubjectoffering" o ON o.id = tr.offering_id WHERE tr.user_id = "retrobolt_security".current_app_user_id() AND tr.active = true AND (tr.valid_from IS NULL OR tr.valid_from <= CURRENT_DATE) AND (tr.valid_to IS NULL OR tr.valid_to >= CURRENT_DATE)
  ) scoped
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_grade_ids() RETURNS integer[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT pg.id), ARRAY[]::integer[])
  FROM "retrobolt_product_perioddivision" d JOIN "retrobolt_product_periodgrade" pg ON pg.id = d.grade_id
  WHERE d.id = ANY("retrobolt_security".current_division_ids())
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_subject_ids() RETURNS text[] LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  SELECT COALESCE(array_agg(DISTINCT subject_id), ARRAY[]::text[])
  FROM (
    SELECT o.subject_id::text AS subject_id FROM "retrobolt_product_divisionsubjectoffering" o WHERE o.id = ANY("retrobolt_security".current_subject_offering_ids())
  ) scoped
$$;
