END;
$$;
CREATE OR REPLACE FUNCTION "retrobolt_security".current_database_role_matches_app_user(expected_role text) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public, pg_temp AS $$
  WITH matrix_roles(role_name, principal) AS (
    VALUES
      ('retrobolt_db_admin_institution_editor', 'db_admin_institution_editor'),
      ('retrobolt_db_admin_organization_editor', 'db_admin_organization_editor'),
      ('retrobolt_institution_director', 'institution_director'),
      ('retrobolt_institution_helper', 'institution_helper'),
      ('retrobolt_organization_admin', 'organization_admin'),
      ('retrobolt_organization_institution_manager', 'organization_institution_manager'),
      ('retrobolt_organization_network_director', 'organization_network_director'),
      ('retrobolt_organization_owner', 'organization_owner'),
      ('retrobolt_organization_setup_admin', 'organization_setup_admin'),
      ('retrobolt_platform_db_admin', 'platform_db_admin'),
      ('retrobolt_pre_login', 'pre_login'),
      ('retrobolt_student', 'student'),
      ('retrobolt_student_exam_pre_login', 'student_exam_pre_login'),
      ('retrobolt_teacher', 'teacher')
  ), role_principal_bindings(domain, role_key, principal) AS (
    VALUES
      ('__none__', '__none__', '__none__')
  )
  SELECT CASE
    WHEN expected_role = 'retrobolt_schema_owner' THEN true
    WHEN expected_role = 'retrobolt_pre_login' THEN true
    ELSE EXISTS (
      SELECT 1
      FROM matrix_roles mr
      JOIN "retrobolt_product_user" u ON u."id" = "retrobolt_security".current_app_user_id()
      WHERE mr.role_name = expected_role
        AND u.is_active = true
        AND mr.principal <> 'pre_login'
        AND EXISTS (
          SELECT 1
          FROM "retrobolt_product_userrolegrant" AS g JOIN "retrobolt_product_role" AS r ON r.id = g.role_id JOIN "retrobolt_product_userrolegrantscope" AS s ON s.grant_id = g.id LEFT JOIN role_principal_bindings b ON b.domain = r.scope_kind AND b.role_key = r.key WHERE g.user_id = u."id" AND "g"."status" = 'active'
    AND ("g"."starts_on" IS NULL OR "g"."starts_on" <= CURRENT_DATE)
    AND ("g"."ends_on" IS NULL OR "g"."ends_on" >= CURRENT_DATE)
    AND "r"."active" = true
    AND "s"."scope_type" = "r"."scope_kind" AND (r.key = mr.principal OR b.principal = mr.principal)
        )
    )
  END
$$;
